// ── Draft History ──────────────────────────────────────────────────────
(function(){
  let _dhTeam = 'bulls';
  let _dhSort = {col:'year', dir:-1}; // -1 = desc (newest first)

  window.dhSelectTeam = function(team) {
    _dhTeam = team;
    document.querySelectorAll('.dh-team-btn').forEach(b => {
      b.classList.toggle('active', b.dataset.team === team);
    });
    dhUpdateStats();
    dhRender();
  };

  window.dhReset = function() {
    document.getElementById('dh-search').value = '';
    document.getElementById('dh-round').value = '';
    document.getElementById('dh-type').value = '';
    document.getElementById('dh-era').value = '';
    dhRender();
  };

  window.dhSort = function(col) {
    if (_dhSort.col === col) _dhSort.dir *= -1;
    else { _dhSort.col = col; _dhSort.dir = col === 'year' ? -1 : 1; }
    // Update header classes
    document.querySelectorAll('.dh-table th[id]').forEach(th => {
      th.classList.remove('sort-asc','sort-desc');
    });
    const th = document.getElementById('dhth-' + col);
    if (th) th.classList.add(_dhSort.dir === 1 ? 'sort-asc' : 'sort-desc');
    dhRender();
  };

  function dhGetRows() {
    if (!window.DRAFT_HISTORY) return [];
    const td = DRAFT_HISTORY[_dhTeam];
    if (!td) return [];
    // own picks: [year,round,pick,player,pos,ht,wt,age,school,class_note,trade_note,yos]
    // trade_note=='' means own pick, else acquired
    const own = (td.picks||[]).map(r => ({...dhRow(r), type:'own'}));
    const acq = (td.acq||[]).map(r => ({...dhRow(r), type:'acq'}));
    return [...own, ...acq];
  }

  function dhRow(r) {
    return {
      year: r[0], round: r[1], pick: r[2], player: r[3],
      pos: r[4], ht: r[5], wt: r[6], age: r[7],
      school: r[8], class_note: r[9], trade_note: r[10],
      yos: parseInt(r[11]) || 0
    };
  }

  function dhFilter(rows) {
    const q = (document.getElementById('dh-search')?.value||'').toLowerCase();
    const round = document.getElementById('dh-round')?.value||'';
    const type  = document.getElementById('dh-type')?.value||'';
    const era   = document.getElementById('dh-era')?.value||'';

    return rows.filter(r => {
      if (q && !r.player.toLowerCase().includes(q) && !r.school.toLowerCase().includes(q)) return false;
      if (round === '1' && r.round !== '1') return false;
      if (round === '2' && r.round === '1') return false;
      if (type === 'own' && r.type !== 'own') return false;
      if (type === 'acq' && r.type !== 'acq') return false;
      const yr = parseInt(r.year);
      if (era === '2010' && yr < 2010) return false;
      if (era === '2000' && (yr < 2000 || yr >= 2010)) return false;
      if (era === '1990' && (yr < 1990 || yr >= 2000)) return false;
      if (era === 'pre1990' && yr >= 1990) return false;
      return true;
    });
  }

  function dhSortRows(rows) {
    const col = _dhSort.col, dir = _dhSort.dir;
    return [...rows].sort((a,b) => {
      let av = a[col], bv = b[col];
      if (col === 'year' || col === 'round' || col === 'pick' || col === 'yos') {
        av = parseInt(av)||0; bv = parseInt(bv)||0;
      } else {
        av = (av||'').toLowerCase(); bv = (bv||'').toLowerCase();
      }
      return av < bv ? -dir : av > bv ? dir : 0;
    });
  }

  window.dhRender = function() {
    const tbody = document.getElementById('dh-tbody');
    const footer = document.getElementById('dh-footer');
    if (!tbody) return;

    const allRows = dhGetRows();
    const filtered = dhSortRows(dhFilter(allRows));

    tbody.innerHTML = filtered.map(r => {
      const isR1 = r.round === '1';
      const isAcq = r.type === 'acq';
      const yosClass = r.yos === 0 ? 'dh-yos-0' : r.yos >= 10 ? 'dh-yos-hi' : '';
      const rowClass = isAcq ? 'dh-row-acq' : '';
      const pickClass = isR1 ? 'dh-pick-r1' : '';
      const via = r.trade_note ? '<span class="dh-badge dh-badge-acq">ACQ</span> ' + r.trade_note : '';
      return `<tr class="${rowClass}">
        <td class="dh-yr">${r.year}</td>
        <td>${r.round}</td>
        <td class="${pickClass}">#${r.pick}</td>
        <td class="dh-player">${r.player}</td>
        <td>${r.pos}</td>
        <td>${r.ht}</td>
        <td>${r.school||'—'}</td>
        <td class="${yosClass}">${r.yos > 0 ? r.yos : '—'}</td>
        <td class="dh-via">${via}</td>
      </tr>`;
    }).join('');

    if (footer) footer.textContent = `Showing ${filtered.length} of ${allRows.length} records`;
  };

  function dhUpdateStats() {
    const bar = document.getElementById('dh-stats-bar');
    if (!bar || !window.DRAFT_HISTORY) return;
    const td = DRAFT_HISTORY[_dhTeam];
    if (!td) return;
    const picks = td.picks||[], acq = td.acq||[];
    const r1 = picks.filter(r=>r[1]==='1').length;
    const years = [...picks,...acq].map(r=>parseInt(r[0]));
    const minYr = Math.min(...years), maxYr = Math.max(...years);
    const starPlayers = picks.filter(r=>parseInt(r[11])>=10);
    bar.innerHTML = `
      <div class="dh-stat"><span class="dh-stat-val">${picks.length}</span><span class="dh-stat-lbl">Own Picks</span></div>
      <div class="dh-stat-divider"></div>
      <div class="dh-stat"><span class="dh-stat-val">${r1}</span><span class="dh-stat-lbl">R1 Own</span></div>
      <div class="dh-stat-divider"></div>
      <div class="dh-stat"><span class="dh-stat-val">${acq.length}</span><span class="dh-stat-lbl">Acquired</span></div>
      <div class="dh-stat-divider"></div>
      <div class="dh-stat"><span class="dh-stat-val">${picks.length+acq.length}</span><span class="dh-stat-lbl">Total</span></div>
      <div class="dh-stat-divider"></div>
      <div class="dh-stat"><span class="dh-stat-val">${starPlayers.length}</span><span class="dh-stat-lbl">10+ Yr Players</span></div>
      <div class="dh-stat-divider"></div>
      <div class="dh-stat"><span class="dh-stat-val">${minYr}–${maxYr}</span><span class="dh-stat-lbl">Span</span></div>
    `;
  }

  // init on switchTeam('draft-history')
  window._dhInit = function() {
    dhUpdateStats();
    dhRender();
    // set default sort header
    const th = document.getElementById('dhth-year');
    if (th) th.classList.add('sort-desc');
  };
})();


(function(){
  var el = document.getElementById('draft-countdown');
  if (!el) return;
  var draft = new Date('2026-06-23T20:00:00-04:00'); // 8PM ET
  var now   = new Date();
  var diff  = Math.ceil((draft - now) / 86400000);
  if (diff > 1)       el.textContent = diff + ' days away';
  else if (diff === 1) el.textContent = 'tomorrow!';
  else if (diff === 0) el.textContent = 'TONIGHT — 8PM ET!';
  else                 el.textContent = 'complete';
})();
